<?php
/**
 * LTMS Deploy Webhook v2 — with direct file patch fallback
 */

define( 'DEPLOY_TOKEN',   'ltms_deploy_2026_s3cur3_t0k3n_x9z' );
define( 'PLUGIN_PATH',    __DIR__ . '/wp-content/plugins/lt-marketplace-suite' );
define( 'LOG_FILE',       __DIR__ . '/ltms-deploy.log' );
define( 'MAX_LOG_LINES',  500 );

header( 'Content-Type: text/plain; charset=utf-8' );
header( 'Cache-Control: no-store, no-cache, must-revalidate' );

$token = $_GET['token'] ?? ($_SERVER['HTTP_X_DEPLOY_TOKEN'] ?? '');
if ( empty( $token ) || ! hash_equals( DEPLOY_TOKEN, $token ) ) {
    http_response_code( 403 );
    echo "Forbidden: invalid token\n";
    exit;
}

$ts = date( 'Y-m-d H:i:s' );
echo "[{$ts}] Deploy webhook triggered\n";
echo "PHP: " . PHP_VERSION . "\n";
echo "PLUGIN_PATH: " . PLUGIN_PATH . "\n";
echo "Path exists: " . ( is_dir( PLUGIN_PATH ) ? 'YES' : 'NO' ) . "\n";
echo "Has .git: " . ( is_dir( PLUGIN_PATH . '/.git' ) ? 'YES' : 'NO' ) . "\n\n";

// ── 1. Try git fetch + reset ──────────────────────────────────────────────────
if ( is_dir( PLUGIN_PATH . '/.git' ) ) {
    echo "--- git fetch + reset ---\n";
    $cmd = 'cd ' . escapeshellarg( PLUGIN_PATH )
        . ' && git fetch origin 2>&1'
        . ' && git reset --hard origin/main 2>&1'
        . ' && git log --oneline -3 2>&1';
    $output = shell_exec( $cmd );
    echo $output . "\n";
} else {
    echo "ERROR: No .git directory — using direct file patch\n";
}

// ── 2. Direct file patch (always runs as safety net) ─────────────────────────
echo "--- Direct file patch ---\n";
$files = [
    'includes/frontend/views/view-kyc.php' => base64_decode(''),
    'includes/frontend/class-ltms-dashboard-logic.php' => base64_decode(''),
];
foreach ( $files as $rel => $content ) {
    $path = PLUGIN_PATH . '/' . $rel;
    if ( ! file_exists( dirname( $path ) ) ) { echo "DIR MISSING: $rel\n"; continue; }
    $bytes = file_put_contents( $path, $content );
    echo ( $bytes !== false ? "OK  $rel ({$bytes}b)" : "ERR $rel" ) . "\n";
    if ( function_exists('opcache_invalidate') ) opcache_invalidate( $path, true );
}

// ── 3. OPcache flush ─────────────────────────────────────────────────────────
echo "\n--- OPcache ---\n";
if ( function_exists( 'opcache_reset' ) ) {
    echo "opcache_reset: " . ( opcache_reset() ? "OK ✓" : "FAILED" ) . "\n";
} else {
    echo "opcache_reset: not available\n";
}

// ── 4. Verify ────────────────────────────────────────────────────────────────
echo "\n--- Verify ---\n";
$kyc = PLUGIN_PATH . '/includes/frontend/views/view-kyc.php';
if ( file_exists( $kyc ) ) {
    $c = file_get_contents( $kyc );
    echo "view-kyc.php: " . filesize($kyc) . "b\n";
    echo "  bank block: " . (strpos($c,'ltms-kyc-rep-legal-name')!==false ? 'YES ✓' : 'NO ✗') . "\n";
    echo "  CLABE: " . (strpos($c,'ltms-kyc-account-number')!==false ? 'YES ✓' : 'NO ✗') . "\n";
}
$dl = PLUGIN_PATH . '/includes/frontend/class-ltms-dashboard-logic.php';
if ( file_exists( $dl ) ) {
    $c = file_get_contents( $dl );
    echo "dashboard-logic.php: " . filesize($dl) . "b\n";
    echo "  upload handler: " . (strpos($c,'ajax_upload_kyc_document')!==false ? 'YES ✓' : 'NO ✗') . "\n";
}

// ── Log ───────────────────────────────────────────────────────────────────────
$log_line = "[{$ts}] Deploy from " . ($_SERVER['REMOTE_ADDR'] ?? 'unknown') . "\n---\n";
file_put_contents( LOG_FILE, $log_line, FILE_APPEND | LOCK_EX );
$lines = @file( LOG_FILE );
if ( $lines && count( $lines ) > MAX_LOG_LINES ) {
    file_put_contents( LOG_FILE, implode( '', array_slice( $lines, -MAX_LOG_LINES ) ), LOCK_EX );
}

echo "\nDeploy OK [{$ts}]\n";
